<span class="line">    <span class="token keyword">const</span> record <span class="token operator">=</span> Record<span class="token punctuation">.</span><span class="token function">getRecordForWorkout</span><span class="token punctuation">(</span>workoutId<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
